<div class="topbar"><div class="topbar-inner"><div class="topbar-left"><span class="topbar-breadcrumb"><i class="bi bi-pencil-square"></i> Sales / Edit Opportunity</span></div></div></div>
<main class="main-content"><section class="sales-shell"><div class="sales-hero"><div><div class="sales-kicker">Engagement Pipeline</div><h1>Edit Opportunity</h1><p>Perbarui stage, deal value, probability, dan jadwal follow-up.</p></div><a class="sales-btn secondary" href="<?= app_url('sales/opportunities'); ?>"><i class="bi bi-arrow-left"></i> Back</a></div><div class="sales-grid"><article class="sales-card span-7"><form class="sales-form" action="<?= app_url('sales/opportunities/update/'.(int)$opportunity['id']); ?>" method="POST"><div class="sales-field full"><label>Title</label><input name="title" required value="<?= htmlspecialchars($opportunity['title']); ?>"></div><div class="sales-field"><label>Client</label><input name="client_name" value="<?= htmlspecialchars($opportunity['client_name']); ?>"></div><div class="sales-field"><label>Lead</label><select name="lead_id"><option value="">Tanpa lead</option><?php foreach($leads as $l): ?><option value="<?= (int)$l['id']; ?>" <?= (int)$opportunity['lead_id']===(int)$l['id']?'selected':''; ?>><?= htmlspecialchars($l['company_name']); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Service</label><select name="service_id"><option value="">Pilih service</option><?php foreach($services as $s): ?><option value="<?= (int)$s['id']; ?>" <?= (int)$opportunity['service_id']===(int)$s['id']?'selected':''; ?>><?= htmlspecialchars($s['name']); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Stage</label><select name="stage"><?php foreach(['inquiry','qualification','consultation','proposal','negotiation','won','lost'] as $s): ?><option value="<?= $s; ?>" <?= $opportunity['stage']===$s?'selected':''; ?>><?= sales_label($s); ?></option><?php endforeach; ?></select></div><div class="sales-field"><label>Deal Value</label><input name="deal_value" type="number" step="1000" value="<?= htmlspecialchars($opportunity['deal_value']); ?>"></div><div class="sales-field"><label>Probability %</label><input name="probability" type="number" min="0" max="100" value="<?= (int)$opportunity['probability']; ?>"></div><div class="sales-field"><label>Expected Close</label><input name="expected_close_date" type="date" value="<?= htmlspecialchars($opportunity['expected_close_date'] ?? ''); ?>"></div><div class="sales-field"><label>Next Follow-up</label><input name="next_followup_date" type="date" value="<?= htmlspecialchars($opportunity['next_followup_date'] ?? ''); ?>"></div><div class="sales-field"><label>Assigned</label><select name="assigned_user_id"><option value="">Unassigned</option><?php foreach($users as $u): ?><option value="<?= (int)$u['id']; ?>" <?= (int)$opportunity['assigned_user_id']===(int)$u['id']?'selected':''; ?>><?= htmlspecialchars($u['full_name'] ?: $u['username']); ?></option><?php endforeach; ?></select></div><div class="sales-field full"><label>Lost Reason</label><input name="lost_reason" value="<?= htmlspecialchars($opportunity['lost_reason']); ?>"></div><div class="sales-field full"><label>Notes</label><textarea name="notes"><?= htmlspecialchars($opportunity['notes']); ?></textarea></div><div class="sales-field full"><button class="sales-btn" type="submit"><i class="bi bi-save"></i> Update Opportunity</button></div></form></article></div></section></main><footer class="app-footer"><span>&copy; <?= date('Y'); ?> NovaTrack Riksa</span></footer><?php require __DIR__.'/styles.php'; ?></body></html>
